def compute_score() -> tuple[str, float]:
    slide_number = 11
    # Check for non-textbox changes
    unrelated_mods = []
    # Removed shapes/elements
    for before, after in ppt_diff.modified_slides:
        if after.slide_number == slide_number:
            if after.element_count < before.element_count:
                unrelated_mods.append("Elements removed from slide 11.")
    # Added/removed/modified charts -- check via python-pptx
    from pptx import Presentation
    prs_before = Presentation(original_ppt_path)
    prs_after = Presentation(modified_ppt_path)
    slide_b = prs_before.slides[slide_number-1]
    slide_a = prs_after.slides[slide_number-1]
    def count_charts(slide):
        return sum(1 for shape in slide.shapes if shape.has_chart)
    if count_charts(slide_b) != count_charts(slide_a):
        unrelated_mods.append("Chart count changed on slide 11.")
    # Check for major formatting change (not required by task)
    if slide_b.background.fill.type != slide_a.background.fill.type:
        unrelated_mods.append("Background fill changed on slide 11.")
    if unrelated_mods:
        return ("; ".join(unrelated_mods), 0.0)
    else:
        return ("No unrelated modifications to slide 11.", 1.0)

def compute_score() -> tuple[str, float]:
    # Only slide 5 (slide_number=5) should be altered
    problematic_mods = []
    for (old, new) in ppt_diff.modified_slides:
        if old.slide_number != 11:
            # Check if nontrivial changes happened
            major = False
            # Check notes, title, number of elements (as proxy)
            if old.title != new.title or (old.notes or "") != (new.notes or "") or old.element_count != new.element_count:
                major = True
            if major:
                problematic_mods.append(old.slide_number)
    # Check for added/removed slides
    added = [s.slide_number for s in ppt_diff.added_slides if s.slide_number != 11]
    removed = [s.slide_number for s in ppt_diff.removed_slides if s.slide_number != 11]
    if problematic_mods or added or removed:
        return f"Slides other than 11 changed: modified={problematic_mods}, added={added}, removed={removed}.", 0.0
    return "No extraneous changes to other slides.", 1.0
